### Diagnostic Checks
```rust
struct SourceDiagnostics {
    checks: Vec<DiagnosticCheck>,
}

struct DiagnosticCheck {
    name: String,
    status: CheckStatus,
    message: String,
    remediation: Option<String>,
}

enum CheckStatus {
    Pass,
    Warn,
    Fail,
}

impl SourceDiagnostics {
    async fn run_all(source: &SourceDefinition) -> Self {
        let mut checks = Vec::new();

        // Check 1: SSH connectivity
        checks.push(Self::check_ssh_connectivity(source).await);

        // Check 2: rsync availability
        checks.push(Self::check_rsync_available(source).await);

        // Check 3: Remote paths exist
        for path in &source.paths {
            checks.push(Self::check_remote_path(source, path).await);
        }

        // Check 4: Local storage writable
        checks.push(Self::check_local_storage().await);

        // Check 5: Last sync status
        checks.push(Self::check_last_sync(source).await);

        Self { checks }
    }

    async fn check_ssh_connectivity(source: &SourceDefinition) -> DiagnosticCheck {
        let host = source.host.as_ref().unwrap_or(&"".to_string());

        let result = Command::new("ssh")
            .args(["-o", "ConnectTimeout=5", "-o", "BatchMode=yes", host, "true"])
            .output()
            .await;

        match result {
            Ok(output) if output.status.success() => DiagnosticCheck {
                name: "SSH Connectivity".into(),
                status: CheckStatus::Pass,
                message: format!("Connected to {} successfully", host),
                remediation: None,
            },
            Ok(output) => {
                let stderr = String::from_utf8_lossy(&output.stderr);
                let remediation = if stderr.contains("Permission denied") {
                    Some("Check SSH key is added to remote authorized_keys".into())
                } else if stderr.contains("Connection refused") {
                    Some("Verify SSH server is running on remote host".into())
                } else {
                    Some("Check SSH configuration and network connectivity".into())
                };

                DiagnosticCheck {
                    name: "SSH Connectivity".into(),
                    status: CheckStatus::Fail,
                    message: stderr.trim().to_string(),
                    remediation,
                }
            }
            Err(e) => DiagnosticCheck {
                name: "SSH Connectivity".into(),
                status: CheckStatus::Fail,
                message: format!("Failed to run ssh: {}", e),
                remediation: Some("Ensure SSH client is installed".into()),
            },
        }
    }
}
```

